/*
 * SHIM DE DESENVOLUPAMENT — substitut mínim d'Alpine.js (NO és Alpine real).
 *
 * Per què: l'entorn de bastida no té accés a la xarxa per descarregar la
 * llibreria oficial. Aquest shim implementa un subconjunt (x-data, x-text,
 * x-show, @click) perquè la UI funcioni localment sense CDN durant la Fase 1.
 *
 * ABANS DE PRODUCCIÓ: substitueix aquest fitxer per la build oficial d'Alpine 3
 * (vegeu public/assets/vendor/README.md). L'API de directives és compatible.
 */
(function () {
    'use strict';

    function reactive(obj, onChange) {
        return new Proxy(obj, {
            set: function (t, k, v) { t[k] = v; onChange(); return true; },
            get: function (t, k) { return t[k]; }
        });
    }

    function evalExpr(expr, scope) {
        try {
            return new Function('with(this){return (' + expr + ')}').call(scope);
        } catch (e) { return undefined; }
    }

    function runStmt(expr, scope) {
        try {
            new Function('with(this){' + expr + '}').call(scope);
        } catch (e) { /* silenci en dev */ }
    }

    function bindRoot(root) {
        var data = evalExpr(root.getAttribute('x-data') || '{}', {}) || {};

        function render() {
            root.querySelectorAll('[x-text]').forEach(function (el) {
                var val = evalExpr(el.getAttribute('x-text'), state);
                el.textContent = (val === undefined || val === null) ? '' : val;
            });
            root.querySelectorAll('[x-show]').forEach(function (el) {
                el.style.display = evalExpr(el.getAttribute('x-show'), state) ? '' : 'none';
            });
        }

        var state = reactive(data, render);

        root.querySelectorAll('[\\@click], [x-on\\:click]').forEach(function (el) {
            var expr = el.getAttribute('@click') || el.getAttribute('x-on:click');
            el.addEventListener('click', function () { runStmt(expr, state); });
        });

        render();
    }

    function init() {
        document.querySelectorAll('[x-data]').forEach(bindRoot);
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();
